{"cmd":"cd /app && rm -f image.ppm && ./mystery > /dev/null 2>&1 && awk 'NR>3{print}' image.ppm | awk '{r[NR]=$1; g[NR]=$2; b[NR]=$3} END {
  # Print corners and center
  printf "Top-left (0,0): %d %d %d\n", r[1], g[1], b[1]
  printf "Top-right (799,0): %d %d %d\n", r[800], g[800], b[800]
  printf "Bottom-left (0,599): %d %d %d\n", r[472001], g[472001], b[472001]
  printf "Bottom-right (799,599): %d %d %d\n", r[480000], g[480000], b[480000]
  printf "Center (399,299): %d %d %d\n", r[240001], g[240001], b[240001]
}'"}

{"cmd":"cd /app && rm -f image.ppm && ./mystery > /dev/null 2>&1 && awk 'NR>3{print}' image.ppm | awk '{r[NR]=$1; g[NR]=$2; b[NR]=$3} END {
  # Sample every 80 pixels in first row
  for(col=0; col<800; col+=80) {
    idx = col+1
    printf "Row 0, Col %d: %d %d %d\n", col, r[idx], g[idx], b[idx]
  }
}'"}

{"cmd":"cd /app && rm -f image.ppm && ./mystery > /dev/null 2>&1 && awk 'NR>3{print}' image.ppm | awk '{r[NR]=$1; g[NR]=$2; b[NR]=$3} END {
  # Sample middle column (col=400) across all rows
  for(row=0; row<600; row+=30) {
    idx = row*800 + 400
    printf "Row %d, Col 400: %d %d %d\n", row, r[idx], g[idx], b[idx]
  }
}'"}
